messages.content:
Kamu adalah asisten AI pembuat game edukasi. Tugasmu mengubah prompt sederhana dari guru menjadi JSON game edukasi yang lengkap dan valid sesuai schema v1.2.

Output HARUS berupa JSON valid tanpa teks tambahan, tanpa markdown code block.

ATURAN KETAT untuk setiap field:
- schema_version: selalu "1.2"
- game_id: format "game_{subject}{grade}_{topic}_{number}" contoh: "game_phys10_kin_word_001"
- game_type: HANYA "word_game" | "puzzle_game" | "sim_lab"
- metadata:
  - subject: HANYA "Fisika" | "Kimia" | "Biologi" | "Matematika"
  - grade_level: HANYA "SMA-10" | "SMA-11" | "SMA-12"
  - difficulty: integer 1-5 (BUKAN string seperti "Sedang")
  - estimated_duration_minutes: integer 5-60
  - learning_objectives: array of string, 1-5 item, tanpa prefix dash
  - language: selalu "id"
- presentation: SEMUA sub-field harus OBJECT, bukan string
  - opening: OBJECT {id, show_once, title, story, image_description, cta_text}
  - visual_element: OBJECT {theme_name, theme_preset, mood, color_palette, setting_description, art_style}
    - theme_preset: HANYA "classroom"|"scifi_neon"|"nature"|"retro"|"minimal"|"adventure"
    - color_palette: OBJECT {primary, secondary, background, accent, text} semua format #RRGGBB
  - instructions: OBJECT {id, trigger{type,position,icon,label}, steps[{step,text}]}
  - hint: OBJECT {id, scope, trigger{type,after_seconds,dismissible,reusable,manual_trigger_available}, content{title,strategy,formula,example,hint_image_description}}
  - audio: OBJECT {enabled, tracks[{id,event,description}]}
    - event: HANYA "on_correct_action"|"on_wrong_action"|"on_win"|"on_lose"|"background"
- payload: HARUS sesuai game_type
  - word_game: {instruction, word_bank[], questions[{id,type,prompt,answer,explanation}]}
    - type soal: "fill_blank"|"match_pair"|"crossword_clue"|"unscramble"
  - puzzle_game: {instruction, stages[{stage_id,title,description,challenges[{id,type,prompt,answer,explanation}]}]}
    - type challenge: "multiple_choice"|"drag_sort"|"drag_match"|"calculate"|"true_false"
  - sim_lab: {instruction, variables[{name,label,unit,min,max,default,step}], formula{expression,description}, sim_steps[{step,action}], analysis_questions[{id,question,expected_answer}]}
- win_lose_condition: OBJECT {applicable, win{description,logic,feedback_text,feedback_audio}, lose{description,logic,feedback_text,feedback_audio,retry_allowed}}
- gameplay_parameters: OBJECT {scoring{}, lives, time_limit_seconds, pass_threshold}

Variasikan game_type secara merata. Buat konten edukatif yang akurat dan game yang engaging.

{
  "schema_version": "1.2",
  "game_id": "game_phys10_projectile_001",
  "game_type": "puzzle_game",
  "metadata": {
    "subject": "Fisika",
    "grade_level": "SMA-10",
    "difficulty": 3,
    "estimated_duration_minutes": 20,
    "learning_objectives": [
      "Memahami konsep gerak parabola dalam sistem koordinat dua dimensi",
      "Mengidentifikasi komponen kecepatan awal pada sumbu x dan y",
      "Menghitung waktu tempuh, ketinggian maksimum, dan jarak horizontal maksimum",
      "Menerapkan persamaan gerak parabola dalam permainan fisika"
    ],
    "language": "id"
  },
  "presentation": {
    "opening": {
      "id": "opn_parabola_intro",
      "show_once": true,
      "title": "Laboratorium Gerak Parabola",
      "story": "Anda adalah seorang ilmuwan muda di laboratorium fisika virtual. Tugas Anda adalah menembakkan bola peluru ke target dengan presisi menggunakan prinsip gerak parabola.",
      "image_description": "Laboratorium modern dengan peralatan fisika, layar komputer besar menampilkan lintasan parabola, dan senjata tembak kecil dengan pengatur sudut dan kecepatan",
      "cta_text": "Mulai Eksperimen"
    },
    "visual_element": {
      "theme_name": "Science Lab Adventure",
      "theme_preset": "scifi_neon",
      "mood": "eksperimental dan futuristik",
      "color_palette": {
        "primary": "#00a8cc",
        "secondary": "#fbc531",
        "background": "#192a56",
        "accent": "#9c88ff",
        "text": "#f5f6fa"
      },
      "setting_description": "Laboratorium fisika dengan layar holografik menampilkan simulasi lintasan parabola",
      "art_style": "Minimalis futuristik dengan elemen neon"
    },
    "instructions": {
      "id": "inst_parabola",
      "trigger": {
        "type": "hover",
        "position": "top-center",
        "icon": "info",
        "label": "Petunjuk Permainan"
      },
      "steps": [
        {
          "step": 1,
          "text": "Atur sudut elevasi dan kecepatan awal peluru"
        },
        {
          "step": 2,
          "text": "Hitung parameter gerak parabola sesuai tantangan"
        },
        {
          "step": 3,
          "text": "Temukan jawaban yang benar untuk melanjutkan"
        }
      ]
    },
    "hint": {
      "id": "hint_parabola",
      "scope": "global",
      "trigger": {
        "type": "timer",
        "after_seconds": 30,
        "dismissible": true,
        "reusable": true,
        "manual_trigger_available": true
      },
      "content": {
        "title": "Rumus Gerak Parabola",
        "strategy": "Gunakan rumus gerak parabola untuk menghitung waktu tempuh, ketinggian maksimum, dan jarak horizontal maksimum",
        "formula": "vx = v0.cos(θ), vy = v0.sin(θ) - gt, xmax = (v0².sin(2θ))/g, ymax = (v0².sin²(θ))/(2g)",
        "example": "Jika v0=20m/s dan θ=30°, maka vx = 20.cos(30°) ≈ 17.32 m/s",
        "hint_image_description": "Diagram gerak parabola dengan label komponen kecepatan dan titik penting lintasan"
      }
    },
    "audio": {
      "enabled": true,
      "tracks": [
        {
          "id": "bg_laboratory",
          "event": "background",
          "description": "Musik latar laboratorium futuristik"
        },
        {
          "id": "snd_success",
          "event": "on_correct_action",
          "description": "Suara efek berhasil"
        },
        {
          "id": "snd_failure",
          "event": "on_wrong_action",
          "description": "Suara efek kesalahan"
        },
        {
          "id": "snd_win",
          "event": "on_win",
          "description": "Suara kemenangan"
        }
      ]
    }
  },
  "payload": {
    "instruction": "Selesaikan tantangan-tantangan berikut terkait gerak parabola. Gunakan rumus-rumus fisika untuk menghitung nilai-nilai yang diminta.",
    "stages": [
      {
        "stage_id": "stage_1",
        "title": "Dasar Gerak Parabola",
        "description": "Pelajari komponen kecepatan awal dalam gerak parabola",
        "challenges": [
          {
            "id": "chal_1_1",
            "type": "calculate",
            "prompt": "Sebuah peluru ditembakkan dengan kecepatan awal 20 m/s pada sudut 30° terhadap horizontal. Hitung komponen kecepatan awal pada sumbu-x (vx). Gunakan cos(30°) = 0.866",
            "answer": 17.32,
            "explanation": "Komponen kecepatan pada sumbu-x: vx = v0 × cos(θ) = 20 × cos(30°) = 20 × 0.866 = 17.32 m/s"
          },
          {
            "id": "chal_1_2",
            "type": "calculate",
            "prompt": "Hitung komponen kecepatan awal pada sumbu-y (vy) untuk peluru yang sama. Gunakan sin(30°) = 0.5",
            "answer": 10,
            "explanation": "Komponen kecepatan pada sumbu-y: vy = v0 × sin(θ) = 20 × sin(30°) = 20 × 0.5 = 10 m/s"
          }
        ]
      },
      {
        "stage_id": "stage_2",
        "title": "Parameter Lintasan",
        "description": "Hitung parameter penting dalam gerak parabola",
        "challenges": [
          {
            "id": "chal_2_1",
            "type": "calculate",
            "prompt": "Hitung waktu yang dibutuhkan peluru untuk mencapai ketinggian maksimum. Gunakan g = 10 m/s²",
            "answer": 1,
            "explanation": "Waktu ke ketinggian maksimum: t = vy/g = 10/10 = 1 detik"
          },
          {
            "id": "chal_2_2",
            "type": "calculate",
            "prompt": "Hitung total waktu penerbangan peluru (waktu hingga menyentuh tanah kembali)",
            "answer": 2,
            "explanation": "Total waktu penerbangan = 2 × waktu ke ketinggian maksimum = 2 × 1 = 2 detik"
          }
        ]
      },
      {
        "stage_id": "stage_3",
        "title": "Target Akurasi",
        "description": "Tentukan jarak horizontal maksimum yang dicapai peluru",
        "challenges": [
          {
            "id": "chal_3_1",
            "type": "calculate",
            "prompt": "Hitung jarak horizontal maksimum (x_max) yang dicapai peluru",
            "answer": 34.64,
            "explanation": "Jarak horizontal maksimum: x_max = vx × total_waktu = 17.32 × 2 = 34.64 meter"
          },
          {
            "id": "chal_3_2",
            "type": "multiple_choice",
            "prompt": "Jika sudut elevasi diubah menjadi 45° dengan kecepatan awal tetap 20 m/s, bagaimana pengaruhnya terhadap jarak horizontal maksimum?",
            "answer": "Akan meningkat",
            "options": [
              "Akan meningkat",
              "Akan menurun",
              "Tidak berubah",
              "Tidak dapat ditentukan"
            ],
            "explanation": "Jarak horizontal maksimum mencapai nilai maksimal saat sudut elevasi 45° karena sin(2×45°) = sin(90°) = 1"
          }
        ]
      }
    ]
  },
  "win_lose_condition": {
    "applicable": true,
    "win": {
      "description": "Menyelesaikan semua tantangan dengan benar",
      "logic": "all_challenges_correct",
      "feedback_text": "Selamat! Anda telah memahami konsep gerak parabola dengan baik dan berhasil menyelesaikan semua tantangan.",
      "feedback_audio": "snd_win"
    },
    "lose": {
      "description": "Gagal menjawab lebih dari setengah tantangan",
      "logic": "more_than_half_incorrect",
      "feedback_text": "Anda perlu mempelajari kembali konsep gerak parabola. Coba ulangi latihan ini.",
      "feedback_audio": "snd_failure",
      "retry_allowed": true
    }
  },
  "gameplay_parameters": {
    "scoring": {
      "points_per_correct": 10,
      "points_per_hint_used": -2,
      "bonus_stage_completion": 20
    },
    "lives": 3,
    "time_limit_seconds": 600,
    "pass_threshold": 0.7
  }
}

