{
  "schema_version": "1.2",
  "game_id": "game_phys11_circular_motion_001",
  "game_type": "sim_lab",
  "metadata": {
    "subject": "Fisika",
    "grade_level": "SMA-11",
    "difficulty": 2,
    "estimated_duration_minutes": 15,
    "learning_objectives": [
      "Memahami konsep gerak melingkar beraturan",
      "Menghitung kecepatan sudut dan percepatan sentripetal",
      "Menjelaskan hubungan antara kecepatan linear dan kecepatan sudut"
    ],
    "language": "id"
  },
  "presentation": {
    "opening": {
      "id": "intro_001",
      "show_once": true,
      "title": "Laboratorium Simulasi Gerak Melingkar",
      "story": "Jelajahi fenomena gerak melingkar beraturan melalui simulasi interaktif ini. Kamu akan mengamati bagaimana benda bergerak dalam lintasan lingkaran dengan kecepatan tetap.",
      "image_description": "Ilustrasi laboratorium virtual dengan model 3D roda berputar dan partikel mengikuti lintasan melingkar",
      "cta_text": "Mulai Eksperimen"
    },
    "visual_element": {
      "theme_name": "Science Lab",
      "theme_preset": "minimal",
      "mood": "edukatif dan eksperimental",
      "color_palette": {
        "primary": "#2E86AB",
        "secondary": "#A23B72",
        "background": "#F9F9F9",
        "accent": "#F18F01",
        "text": "#333333"
      },
      "setting_description": "Laboratorium virtual dengan peralatan simulasi gerak melingkar",
      "art_style": "Clean vector graphics dengan elemen ilmiah"
    },
    "instructions": {
      "id": "instr_001",
      "trigger": {
        "type": "on_start",
        "position": "top_center",
        "icon": "info",
        "label": "Petunjuk"
      },
      "steps": [
        {
          "step": 1,
          "text": "Atur parameter simulasi seperti jari-jari lintasan, kecepatan putar, dan waktu pengamatan"
        },
        {
          "step": 2,
          "text": "Lihat hasil simulasi gerak melingkar beraturan secara real-time"
        },
        {
          "step": 3,
          "text": "Jawab pertanyaan analisis berdasarkan data simulasi"
        }
      ]
    },
    "hint": {
      "id": "hint_001",
      "scope": "simulation",
      "trigger": {
        "type": "time_based",
        "after_seconds": 30,
        "dismissible": true,
        "reusable": true,
        "manual_trigger_available": true
      },
      "content": {
        "title": "Tips Simulasi",
        "strategy": "Coba ubah nilai jari-jari dan kecepatan untuk melihat perubahan pada percepatan sentripetal",
        "formula": "v = ωr, ac = v²/r = ω²r",
        "example": "Jika ω = 2 rad/s dan r = 0.5 m, maka v = 1 m/s dan ac = 2 m/s²",
        "hint_image_description": "Diagram yang menunjukkan hubungan antara kecepatan sudut, jari-jari, dan percepatan sentripetal"
      }
    },
    "audio": {
      "enabled": true,
      "tracks": [
        {
          "id": "bg_music",
          "event": "background",
          "description": "Musik latar lembut untuk fokus belajar"
        },
        {
          "id": "success_sound",
          "event": "on_correct_action",
          "description": "Suara positif saat menjawab benar"
        },
        {
          "id": "feedback_sound",
          "event": "on_wrong_action",
          "description": "Suara lembut saat membutuhkan bantuan"
        }
      ]
    }
  },
  "payload": {
    "instruction": "Gunakan simulasi ini untuk memahami hubungan antara variabel dalam gerak melingkar beraturan. Atur parameter dan amati hasilnya.",
    "variables": [
      {
        "name": "radius",
        "label": "Jari-jari Lintasan (m)",
        "unit": "m",
        "min": 0.1,
        "max": 2.0,
        "default": 0.5,
        "step": 0.1
      },
      {
        "name": "angular_velocity",
        "label": "Kecepatan Sudut (rad/s)",
        "unit": "rad/s",
        "min": 0.5,
        "max": 5.0,
        "default": 2.0,
        "step": 0.1
      },
      {
        "name": "time",
        "label": "Waktu Pengamatan (s)",
        "unit": "s",
        "min": 1,
        "max": 10,
        "default": 5,
        "step": 1
      }
    ],
    "formula": {
      "expression": "v = ωr; ac = v²/r = ω²r; T = 2π/ω",
      "description": "Rumus-rumus utama dalam gerak melingkar beraturan"
    },
    "sim_steps": [
      {
        "step": 1,
        "action": "Inisialisasi simulasi dengan parameter awal"
      },
      {
        "step": 2,
        "action": "Tampilkan partikel bergerak melingkar dengan kecepatan sudut tertentu"
      },
      {
        "step": 3,
        "action": "Hitung dan tampilkan nilai-nilai fisika seperti kecepatan linear, percepatan sentripetal, dan periode"
      },
      {
        "step": 4,
        "action": "Tampilkan grafik perubahan posisi terhadap waktu"
      }
    ],
    "analysis_questions": [
      {
        "id": "aq_001",
        "question": "Bagaimana hubungan antara kecepatan sudut dan percepatan sentripetal jika jari-jari tetap?",
        "expected_answer": "Percepatan sentripetal sebanding dengan kuadrat kecepatan sudut (ac ∝ ω²)"
      },
      {
        "id": "aq_002",
        "question": "Jika jari-jari lintasan diperbesar dua kali lipat dengan kecepatan sudut tetap, bagaimana perubahan percepatan sentripetal?",
        "expected_answer": "Percepatan sentripetal juga akan meningkat dua kali lipat karena ac = ω²r"
      },
      {
        "id": "aq_003",
        "question": "Berapa periode gerak melingkar jika kecepatan sudut 4 rad/s?",
        "expected_answer": "T = 2π/ω = 2π/4 = π/2 ≈ 1.57 detik"
      }
    ]
  },
  "win_lose_condition": {
    "applicable": true,
    "win": {
      "description": "Menyelesaikan semua pertanyaan analisis dengan benar",
      "logic": "Benar minimal 2 dari 3 pertanyaan analisis",
      "feedback_text": "Selamat! Kamu telah memahami konsep gerak melingkar beraturan dengan baik.",
      "feedback_audio": "on_win"
    },
    "lose": {
      "description": "Gagal menjawab minimal 2 dari 3 pertanyaan analisis",
      "logic": "Benar kurang dari 2 dari 3 pertanyaan analisis",
      "feedback_text": "Pelajari kembali rumus dan konsep gerak melingkar beraturan, lalu coba lagi.",
      "feedback_audio": "on_lose",
      "retry_allowed": true
    }
  },
  "gameplay_parameters": {
    "scoring": {
      "correct_answer": 10,
      "wrong_answer": 0,
      "bonus_for_speed": 5
    },
    "lives": 3,
    "time_limit_seconds": 600,
    "pass_threshold": 60
  }
}

