  "game_id": "game_phys12_circular_motion_001",
  "game_type": "word_game",
  "metadata": {
    "subject": "Fisika",
    "grade_level": "SMA-12",
    "difficulty": 1,
    "estimated_duration_minutes": 8,
    "learning_objectives": [
      "Memahami konsep percepatan sentripetal dalam gerak melingkar",
      "Mengidentifikasi rumus dasar percepatan sentripetal",
